module RefModule(
    input [1:0] A,
    input [1:0] B,
    input Cin,
    output [1:0] Sum,
    output Cout
);// Declare internal wires
wire [1:0] obf_s;
wire c1, c2;

// First bit addition
assign obf_s[0] = A[0] ^ B[0] ^ Cin;
assign c1 = (A[0] & B[0]) | (Cin & (A[0] ^ B[0]));

// Second bit addition
assign obf_s[1] = A[1] ^ B[1] ^ c1;
assign c2 = (A[1] & B[1]) | (c1 & (A[1] ^ B[1]));

// Assign outputs
assign Sum = obf_s;
assign Cout = c2;

endmodule
